import numpy as np

def cosine_sim(a, b):
    a, b = np.asarray(a), np.asarray(b)
    return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b)))

# With normalized embeddings (common), just dot product:
def cosine_sim_fast(a, b):
    return float(np.dot(a, b))

